import ContextManager from '../src/context/ContextManager.js';
import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

describe('ContextManager', () => {
  let contextManager;

  beforeEach(() => {
    contextManager = new ContextManager(4096);
  });

  describe('constructor', () => {
    it('should initialize with default maxTokens', () => {
      const cm = new ContextManager();
      expect(cm.maxTokens).toBe(4096);
    });

    it('should initialize with custom maxTokens', () => {
      const cm = new ContextManager(8192);
      expect(cm.maxTokens).toBe(8192);
    });

    it('should initialize with empty messages array', () => {
      expect(contextManager.messages).toEqual([]);
    });

    it('should initialize with empty fileContexts map', () => {
      expect(contextManager.fileContexts.size).toBe(0);
    });
  });

  describe('addMessage', () => {
    it('should add a user message', () => {
      const message = contextManager.addMessage('user', 'Hello');
      
      expect(message.role).toBe('user');
      expect(message.content).toBe('Hello');
      expect(message.timestamp).toBeInstanceOf(Date);
      expect(message.metadata).toBeDefined();
    });

    it('should add an assistant message', () => {
      const message = contextManager.addMessage('assistant', 'Hi there!');
      
      expect(message.role).toBe('assistant');
      expect(message.content).toBe('Hi there!');
    });

    it('should add a system message', () => {
      const message = contextManager.addMessage('system', 'System initialized');
      
      expect(message.role).toBe('system');
      expect(message.content).toBe('System initialized');
    });

    it('should throw error for invalid role', () => {
      expect(() => {
        contextManager.addMessage('invalid', 'test');
      }).toThrow('Invalid role: invalid');
    });

    it('should throw error for non-string content', () => {
      expect(() => {
        contextManager.addMessage('user', 123);
      }).toThrow('Message content must be a string');
    });

    it('should include metadata in message', () => {
      const metadata = { files: ['test.js'], custom: 'value' };
      const message = contextManager.addMessage('user', 'Test', metadata);
      
      expect(message.metadata.files).toEqual(['test.js']);
      expect(message.metadata.custom).toBe('value');
    });

    it('should estimate tokens if not provided in metadata', () => {
      const message = contextManager.addMessage('user', 'Hello world');
      
      expect(message.metadata.tokens).toBeDefined();
      expect(typeof message.metadata.tokens).toBe('number');
    });

    it('should use provided token count in metadata', () => {
      const message = contextManager.addMessage('user', 'Test', { tokens: 100 });
      
      expect(message.metadata.tokens).toBe(100);
    });

    it('should add message to messages array', () => {
      contextManager.addMessage('user', 'First');
      contextManager.addMessage('assistant', 'Second');
      
      expect(contextManager.messages.length).toBe(2);
      expect(contextManager.messages[0].content).toBe('First');
      expect(contextManager.messages[1].content).toBe('Second');
    });
  });

  describe('getMessages', () => {
    beforeEach(() => {
      contextManager.addMessage('system', 'System message');
      contextManager.addMessage('user', 'User message 1');
      contextManager.addMessage('assistant', 'Assistant message 1');
      contextManager.addMessage('user', 'User message 2');
      contextManager.addMessage('assistant', 'Assistant message 2');
    });

    it('should return all messages', () => {
      const messages = contextManager.getMessages();
      
      expect(messages.length).toBe(5);
    });

    it('should filter messages by role', () => {
      const userMessages = contextManager.getMessages({ role: 'user' });
      
      expect(userMessages.length).toBe(2);
      expect(userMessages[0].content).toBe('User message 1');
      expect(userMessages[1].content).toBe('User message 2');
    });

    it('should limit number of messages', () => {
      const messages = contextManager.getMessages({ limit: 3 });
      
      expect(messages.length).toBe(3);
      expect(messages[0].content).toBe('Assistant message 1');
      expect(messages[2].content).toBe('Assistant message 2');
    });

    it('should return only specified fields', () => {
      const messages = contextManager.getMessages({ fields: ['role', 'content'] });
      
      expect(messages.length).toBe(5);
      expect(messages[0]).toHaveProperty('role');
      expect(messages[0]).toHaveProperty('content');
      expect(messages[0]).not.toHaveProperty('timestamp');
      expect(messages[0]).not.toHaveProperty('metadata');
    });

    it('should combine filters', () => {
      const messages = contextManager.getMessages({ 
        role: 'user', 
        limit: 1 
      });
      
      expect(messages.length).toBe(1);
      expect(messages[0].content).toBe('User message 2');
    });

    it('should return a copy of messages array', () => {
      const messages = contextManager.getMessages();
      messages.push({ role: 'user', content: 'Modified' });
      
      expect(contextManager.messages.length).toBe(5);
    });
  });

  describe('clear', () => {
    it('should clear all messages', () => {
      contextManager.addMessage('user', 'Test');
      contextManager.clear();
      
      expect(contextManager.messages.length).toBe(0);
    });

    it('should clear file contexts', () => {
      contextManager.fileContexts.set('test.js', { content: 'test' });
      contextManager.clear();
      
      expect(contextManager.fileContexts.size).toBe(0);
    });

    it('should reset session ID', () => {
      contextManager.sessionId = 'test-session';
      contextManager.clear();
      
      expect(contextManager.sessionId).toBeNull();
    });
  });

  describe('getMessageCount', () => {
    it('should return 0 for empty context', () => {
      expect(contextManager.getMessageCount()).toBe(0);
    });

    it('should return correct count', () => {
      contextManager.addMessage('user', 'Test 1');
      contextManager.addMessage('assistant', 'Test 2');
      
      expect(contextManager.getMessageCount()).toBe(2);
    });
  });

  describe('getLastMessage', () => {
    it('should return null for empty context', () => {
      expect(contextManager.getLastMessage()).toBeNull();
    });

    it('should return the last message', () => {
      contextManager.addMessage('user', 'First');
      contextManager.addMessage('assistant', 'Last');
      
      const lastMessage = contextManager.getLastMessage();
      expect(lastMessage.content).toBe('Last');
      expect(lastMessage.role).toBe('assistant');
    });
  });

  describe('removeLastMessage', () => {
    it('should return null for empty context', () => {
      expect(contextManager.removeLastMessage()).toBeNull();
    });

    it('should remove and return the last message', () => {
      contextManager.addMessage('user', 'First');
      contextManager.addMessage('assistant', 'Last');
      
      const removed = contextManager.removeLastMessage();
      
      expect(removed.content).toBe('Last');
      expect(contextManager.messages.length).toBe(1);
      expect(contextManager.messages[0].content).toBe('First');
    });
  });

  describe('estimateTokens', () => {
    it('should return 0 for empty string', () => {
      expect(contextManager.estimateTokens('')).toBe(0);
    });

    it('should return 0 for null', () => {
      expect(contextManager.estimateTokens(null)).toBe(0);
    });

    it('should estimate tokens for text', () => {
      const text = 'Hello world'; // 11 characters
      const tokens = contextManager.estimateTokens(text);
      
      expect(tokens).toBe(Math.ceil(11 / 4)); // ~3 tokens
    });

    it('should estimate tokens for longer text', () => {
      const text = 'a'.repeat(100); // 100 characters
      const tokens = contextManager.estimateTokens(text);
      
      expect(tokens).toBe(25); // 100/4 = 25 tokens
    });
  });

  describe('getTotalTokens', () => {
    it('should return 0 for empty context', () => {
      expect(contextManager.getTotalTokens()).toBe(0);
    });

    it('should calculate total tokens from messages', () => {
      contextManager.addMessage('user', 'a'.repeat(40)); // ~10 tokens
      contextManager.addMessage('assistant', 'a'.repeat(80)); // ~20 tokens
      
      const total = contextManager.getTotalTokens();
      expect(total).toBe(30);
    });

    it('should use metadata tokens if available', () => {
      contextManager.addMessage('user', 'test', { tokens: 100 });
      contextManager.addMessage('assistant', 'test', { tokens: 200 });
      
      expect(contextManager.getTotalTokens()).toBe(300);
    });
  });

  describe('truncate', () => {
    beforeEach(() => {
      // Create a context with known token counts
      contextManager = new ContextManager(1000); // 1000 token limit
    });

    it('should not truncate if under token limit', () => {
      contextManager.addMessage('user', 'a'.repeat(100)); // ~25 tokens
      contextManager.addMessage('assistant', 'a'.repeat(100)); // ~25 tokens
      
      const removed = contextManager.truncate();
      
      expect(removed.length).toBe(0);
      expect(contextManager.messages.length).toBe(2);
    });

    it('should truncate old messages when over limit', () => {
      // Add messages that exceed 80% of 1000 tokens (800 tokens)
      for (let i = 0; i < 20; i++) {
        contextManager.addMessage('user', 'a'.repeat(200)); // ~50 tokens each
      }
      
      const removed = contextManager.truncate({ targetTokens: 800 });
      
      expect(removed.length).toBeGreaterThan(0);
      expect(contextManager.getTotalTokens()).toBeLessThanOrEqual(800);
    });

    it('should keep system messages', () => {
      contextManager.addMessage('system', 'System message');
      
      for (let i = 0; i < 20; i++) {
        contextManager.addMessage('user', 'a'.repeat(200)); // ~50 tokens each
      }
      
      contextManager.truncate({ targetTokens: 500 });
      
      const systemMessages = contextManager.messages.filter(m => m.role === 'system');
      expect(systemMessages.length).toBe(1);
      expect(systemMessages[0].content).toBe('System message');
    });

    it('should keep recent messages', () => {
      for (let i = 0; i < 20; i++) {
        contextManager.addMessage('user', 'a'.repeat(200)); // ~50 tokens each
      }
      
      const initialCount = contextManager.messages.length;
      contextManager.truncate({ keepRecentCount: 5, targetTokens: 200 });
      
      // Should have removed some messages
      expect(contextManager.messages.length).toBeLessThan(initialCount);
      
      // Should be within token limit
      expect(contextManager.getTotalTokens()).toBeLessThanOrEqual(200);
    });

    it('should return removed messages', () => {
      for (let i = 0; i < 10; i++) {
        contextManager.addMessage('user', 'a'.repeat(400)); // ~100 tokens each
      }
      
      const removed = contextManager.truncate({ targetTokens: 500 });
      
      expect(removed.length).toBeGreaterThan(0);
      expect(removed[0]).toHaveProperty('role');
      expect(removed[0]).toHaveProperty('content');
    });

    it('should respect keepSystemMessages option', () => {
      contextManager.addMessage('system', 'System message');
      
      for (let i = 0; i < 20; i++) {
        contextManager.addMessage('user', 'a'.repeat(200));
      }
      
      contextManager.truncate({ 
        keepSystemMessages: false, 
        targetTokens: 500 
      });
      
      const systemMessages = contextManager.messages.filter(m => m.role === 'system');
      expect(systemMessages.length).toBe(0);
    });
  });

  describe('isNearTokenLimit', () => {
    beforeEach(() => {
      contextManager = new ContextManager(1000);
    });

    it('should return false when well under limit', () => {
      contextManager.addMessage('user', 'a'.repeat(100)); // ~25 tokens
      
      expect(contextManager.isNearTokenLimit()).toBe(false);
    });

    it('should return true when near limit', () => {
      contextManager.addMessage('user', 'a'.repeat(3600)); // ~900 tokens
      
      expect(contextManager.isNearTokenLimit()).toBe(true);
    });

    it('should respect custom threshold', () => {
      contextManager.addMessage('user', 'a'.repeat(2000)); // ~500 tokens
      
      expect(contextManager.isNearTokenLimit(0.5)).toBe(true);
      expect(contextManager.isNearTokenLimit(0.9)).toBe(false);
    });
  });

  describe('getStats', () => {
    it('should return correct statistics', () => {
      contextManager.addMessage('system', 'System');
      contextManager.addMessage('user', 'User 1');
      contextManager.addMessage('assistant', 'Assistant 1');
      contextManager.addMessage('user', 'User 2');
      
      const stats = contextManager.getStats();
      
      expect(stats.messageCount).toBe(4);
      expect(stats.totalTokens).toBeGreaterThan(0);
      expect(stats.maxTokens).toBe(4096);
      expect(stats.tokenUsagePercent).toBeGreaterThan(0);
      expect(stats.fileCount).toBe(0);
      expect(stats.roleCount).toEqual({
        system: 1,
        user: 2,
        assistant: 1
      });
      expect(stats.isNearLimit).toBe(false);
    });

    it('should show near limit when appropriate', () => {
      contextManager = new ContextManager(100);
      contextManager.addMessage('user', 'a'.repeat(360)); // ~90 tokens
      
      const stats = contextManager.getStats();
      
      expect(stats.isNearLimit).toBe(true);
      expect(stats.tokenUsagePercent).toBeGreaterThanOrEqual(90);
    });
  });

  describe('addFileContext', () => {
    it('should add file context', () => {
      const content = 'console.log("test");';
      const fileContext = contextManager.addFileContext('test.js', content);

      expect(fileContext.path).toBe('test.js');
      expect(fileContext.content).toBe(content);
      expect(fileContext.language).toBe('javascript');
      expect(fileContext.size).toBe(content.length);
      expect(fileContext.addedAt).toBeInstanceOf(Date);
    });

    it('should detect language from file extension', () => {
      contextManager.addFileContext('test.py', 'print("test")');
      const context = contextManager.getFileContext('test.py');
      
      expect(context.language).toBe('python');
    });

    it('should accept custom metadata', () => {
      const lastModified = new Date('2024-01-01');
      const fileContext = contextManager.addFileContext(
        'test.js',
        'code',
        { language: 'typescript', lastModified }
      );

      expect(fileContext.language).toBe('typescript');
      expect(fileContext.lastModified).toEqual(lastModified);
    });

    it('should throw error for invalid file path', () => {
      expect(() => {
        contextManager.addFileContext('', 'content');
      }).toThrow('File path must be a non-empty string');
    });

    it('should throw error for non-string content', () => {
      expect(() => {
        contextManager.addFileContext('test.js', 123);
      }).toThrow('File content must be a string');
    });
  });

  describe('getFileContext', () => {
    it('should return file context if exists', () => {
      contextManager.addFileContext('test.js', 'code');
      const context = contextManager.getFileContext('test.js');
      
      expect(context).not.toBeNull();
      expect(context.path).toBe('test.js');
    });

    it('should return null if not found', () => {
      const context = contextManager.getFileContext('nonexistent.js');
      
      expect(context).toBeNull();
    });
  });

  describe('getAllFileContexts', () => {
    it('should return all file contexts', () => {
      contextManager.addFileContext('file1.js', 'code1');
      contextManager.addFileContext('file2.py', 'code2');
      
      const contexts = contextManager.getAllFileContexts();
      
      expect(contexts.length).toBe(2);
      expect(contexts[0].path).toBe('file1.js');
      expect(contexts[1].path).toBe('file2.py');
    });

    it('should return empty array if no contexts', () => {
      const contexts = contextManager.getAllFileContexts();
      
      expect(contexts).toEqual([]);
    });
  });

  describe('removeFileContext', () => {
    it('should remove file context', () => {
      contextManager.addFileContext('test.js', 'code');
      const removed = contextManager.removeFileContext('test.js');
      
      expect(removed).toBe(true);
      expect(contextManager.getFileContext('test.js')).toBeNull();
    });

    it('should return false if not found', () => {
      const removed = contextManager.removeFileContext('nonexistent.js');
      
      expect(removed).toBe(false);
    });
  });

  describe('session persistence', () => {
    const testSessionsDir = path.join(__dirname, 'test-sessions');
    const testSessionId = 'test-session-' + Date.now();

    beforeEach(async () => {
      // Clean up test sessions directory
      try {
        await fs.rm(testSessionsDir, { recursive: true, force: true });
      } catch (error) {
        // Ignore if doesn't exist
      }
    });

    afterEach(async () => {
      // Clean up test sessions directory
      try {
        await fs.rm(testSessionsDir, { recursive: true, force: true });
      } catch (error) {
        // Ignore if doesn't exist
      }
    });

    describe('save', () => {
      it('should save session to disk', async () => {
        contextManager.addMessage('user', 'Hello');
        contextManager.addMessage('assistant', 'Hi there');
        contextManager.addFileContext('test.js', 'code');

        const filePath = await contextManager.save(testSessionId, testSessionsDir);

        expect(filePath).toContain(testSessionId);
        
        // Verify file exists
        const stats = await fs.stat(filePath);
        expect(stats.isFile()).toBe(true);
      });

      it('should throw error for invalid session ID', async () => {
        await expect(contextManager.save('')).rejects.toThrow(
          'Session ID must be a non-empty string'
        );
      });

      it('should create sessions directory if not exists', async () => {
        await contextManager.save(testSessionId, testSessionsDir);
        
        const stats = await fs.stat(testSessionsDir);
        expect(stats.isDirectory()).toBe(true);
      });

      it('should save all context data', async () => {
        contextManager.addMessage('user', 'Test message');
        contextManager.addFileContext('test.js', 'test code');

        const filePath = await contextManager.save(testSessionId, testSessionsDir);
        const data = await fs.readFile(filePath, 'utf-8');
        const sessionData = JSON.parse(data);

        expect(sessionData.sessionId).toBe(testSessionId);
        expect(sessionData.messages.length).toBe(1);
        expect(sessionData.fileContexts.length).toBe(1);
        expect(sessionData.stats).toBeDefined();
      });
    });

    describe('load', () => {
      it('should load session from disk', async () => {
        // Create and save a session
        contextManager.addMessage('user', 'Original message');
        contextManager.addFileContext('test.js', 'original code');
        await contextManager.save(testSessionId, testSessionsDir);

        // Create new context manager and load
        const newContext = new ContextManager();
        await newContext.load(testSessionId, testSessionsDir);

        expect(newContext.messages.length).toBe(1);
        expect(newContext.messages[0].content).toBe('Original message');
        expect(newContext.fileContexts.size).toBe(1);
        expect(newContext.getFileContext('test.js').content).toBe('original code');
      });

      it('should throw error for non-existent session', async () => {
        const newContext = new ContextManager();
        
        await expect(
          newContext.load('nonexistent-session', testSessionsDir)
        ).rejects.toThrow('Session not found');
      });

      it('should throw error for invalid session ID', async () => {
        await expect(contextManager.load('')).rejects.toThrow(
          'Session ID must be a non-empty string'
        );
      });

      it('should restore Date objects correctly', async () => {
        contextManager.addMessage('user', 'Test');
        await contextManager.save(testSessionId, testSessionsDir);

        const newContext = new ContextManager();
        await newContext.load(testSessionId, testSessionsDir);

        expect(newContext.messages[0].timestamp).toBeInstanceOf(Date);
      });
    });

    describe('listSessions', () => {
      it('should list all saved sessions', async () => {
        const session1 = 'session-1-' + Date.now();
        const session2 = 'session-2-' + Date.now();

        contextManager.addMessage('user', 'Test 1');
        await contextManager.save(session1, testSessionsDir);

        contextManager.clear();
        contextManager.addMessage('user', 'Test 2');
        await contextManager.save(session2, testSessionsDir);

        const sessions = await contextManager.listSessions(testSessionsDir);

        expect(sessions.length).toBe(2);
        expect(sessions[0].sessionId).toBeDefined();
        expect(sessions[0].messageCount).toBeDefined();
      });

      it('should return empty array if no sessions', async () => {
        const sessions = await contextManager.listSessions(testSessionsDir);
        
        expect(sessions).toEqual([]);
      });
    });

    describe('deleteSession', () => {
      it('should delete a session', async () => {
        contextManager.addMessage('user', 'Test');
        await contextManager.save(testSessionId, testSessionsDir);

        const deleted = await contextManager.deleteSession(testSessionId, testSessionsDir);

        expect(deleted).toBe(true);

        // Verify file is deleted
        const sessions = await contextManager.listSessions(testSessionsDir);
        expect(sessions.length).toBe(0);
      });

      it('should return false for non-existent session', async () => {
        const deleted = await contextManager.deleteSession('nonexistent', testSessionsDir);
        
        expect(deleted).toBe(false);
      });

      it('should throw error for invalid session ID', async () => {
        await expect(contextManager.deleteSession('')).rejects.toThrow(
          'Session ID must be a non-empty string'
        );
      });
    });
  });
});
